// Presenter depends on interface only:
public class PocPresenter {
    private final IPocView view;
    private final IPocModel model;
    public PocPresenter(IPocView view, IPocModel model, EventEmitter emitter) {
        this.view = view;
        this.model = model;
        emitter.subscribe(data -> view.setTextArea(data));
        view.addSubmitListener(_ -> submitAction());
    }
}

