// Replace 90-line parser:
private static final ObjectMapper MAPPER = new ObjectMapper();

public static SearchResult toSearchResult(String json) {
    try {
        return MAPPER.readValue(json, SearchResult.class);
    } catch (JsonProcessingException e) {
        log.error("Failed to parse SearchResult JSON: {}", e.getMessage());
        return new SearchResult(); // return empty result, let UI handle gracefully
    }
}

// Java - PocModelTest.java:
@ExtendWith(MockitoExtension.class)
class PocModelTest {
    @Mock IHttpService httpService;
    @Mock EventEmitter eventEmitter;

    @Test
    void action_mapsAllFieldsAndEmitsResponse() throws Exception {
        when(httpService.post(anyMap())).thenReturn("{\"status\":\"ok\"}");
        PocModel model = new PocModel(eventEmitter, httpService);
        model.setStringField(ModelProperties.FIRST_NAME, "Hans");
        model.setStringField(ModelProperties.LAST_NAME, "Mayer");
        model.action();
        ArgumentCaptor<Map<String,String>> captor = ArgumentCaptor.forClass(Map.class);
        verify(httpService).post(captor.capture());
        assertEquals("Hans", captor.getValue().get("FIRST_NAME"));
        verify(eventEmitter).emit("{\"status\":\"ok\"}");
    }

    @Test
    void action_emitsFailure_whenResponseIsEmpty() throws Exception {
        when(httpService.post(anyMap())).thenReturn("");
        new PocModel(eventEmitter, httpService).action();
        verify(eventEmitter).emit("Failed operation");
    }
}

// Vue - Search.spec.js:
import { shallowMount } from '@vue/test-utils';
import Search from '@/components/Search.vue';

describe('searchPerson', () => {
  it('filters results case-insensitively by last name', async () => {
    const wrapper = shallowMount(Search);
    await wrapper.setData({ formdata: { last: 'mayer' } });
    wrapper.vm.searchPerson();
    expect(wrapper.vm.search_result).toHaveLength(1);
    expect(wrapper.vm.search_result[0].name).toBe('Mayer');
  });

  it('returns empty array when no criteria match', async () => {
    const wrapper = shallowMount(Search);
    await wrapper.setData({ formdata: { last: 'zzz_no_match' } });
    wrapper.vm.searchPerson();
    expect(wrapper.vm.search_result).toHaveLength(0);
  });
});

// package.json: replace 'websocket' with 'ws', add 'jsonwebtoken' and 'dotenv'
require('dotenv').config();
const WebSocket = require('ws');
const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret-change-in-production';
const ALLOWED_ORIGINS = new Set((process.env.ALLOWED_ORIGINS || 'http://localhost:8080').split(','));

const wss = new WebSocket.Server({
  port: parseInt(process.env.WS_PORT) || 1337,
  verifyClient: ({ req, origin }, cb) => {
    if (!ALLOWED_ORIGINS.has(origin)) return cb(false, 403, 'Forbidden Origin');
    const token = new URL(req.url, 'ws://x').searchParams.get('token');
    try { req.user = jwt.verify(token, JWT_SECRET); cb(true); }
    catch (e) { cb(false, 401, 'Unauthorized'); }
  }
});

const sessions = new Map(); // sessionId → Set<WebSocket>

wss.on('connection', (ws, req) => {
  const { sessionId } = req.user;
  if (!sessions.has(sessionId)) sessions.set(sessionId, new Set());
  sessions.get(sessionId).add(ws);
  ws.on('message', (data) => {
    try { JSON.parse(data); } catch { return; } // validate JSON
    sessions.get(sessionId).forEach(peer => {
      if (peer !== ws && peer.readyState === WebSocket.OPEN) peer.send(data);
    });
  });
  ws.on('close', () => sessions.get(sessionId)?.delete(ws));
  ws.on('error', err => console.error('WebSocket error:', err));
});

